# scripts/find_commit_for_eval.py
# Find the commit that introduced the behavior tested by a given eval case ID.
import subprocess, re, sys

def commits_mentioning_eval(eval_id: str) -> list[str]:
    """Search commit history for references to an eval case ID."""
    output = subprocess.check_output(
        ["git", "log", "--all", "--oneline", f"--grep=Eval-case:.*{eval_id}"],
        text=True
    )
    return [line.strip() for line in output.splitlines() if line.strip()]

def eval_coverage_report(eval_ids: list[str]) -> dict[str, list[str]]:
    """For each eval ID, find the commits that claim to cover it."""
    coverage = {}
    for eval_id in eval_ids:
        coverage[eval_id] = commits_mentioning_eval(eval_id)
    return coverage

# Example usage:
if __name__ == "__main__":
    eval_id = sys.argv[1] if len(sys.argv) > 1 else "date-format-001"
    commits = commits_mentioning_eval(eval_id)
    if commits:
        print(f"Commits covering {eval_id}:")
        for c in commits:
            print(f"  {c}")
    else:
        print(f"No commits found referencing {eval_id} — this eval case may be untracked")

# scripts/compute_next_version.py
import subprocess, re, sys

BREAKING_PATTERN = re.compile(r'^BREAKING CHANGE:', re.MULTILINE)
MINOR_TYPES = {"feat", "prompt", "tool", "agent", "guardrail"}
PATCH_TYPES = {"fix", "hotfix", "refactor", "perf", "eval", "test", "docs", "chore"}

def git_log_since(tag: str) -> list[str]:
    """Full commit messages since the given tag."""
    return subprocess.check_output(
        ["git", "log", f"{tag}..HEAD", "--format=%B%x00"],
        text=True
    ).split("\x00")

def parse_type(message: str) -> str | None:
    """Extract the type token from a commit message."""
    m = re.match(r'^(\w+)(\([^)]+\))?(!)?:', message)
    return m.group(1) if m else None

def compute_next_version(current_tag: str) -> str:
    major, minor, patch = (int(x) for x in current_tag.lstrip("v").split("."))
    messages = git_log_since(current_tag)

    has_breaking = any(BREAKING_PATTERN.search(m) for m in messages)
    has_minor = any(parse_type(m) in MINOR_TYPES for m in messages)
    has_patch = any(parse_type(m) in PATCH_TYPES for m in messages)

    if has_breaking:
        return f"v{major + 1}.0.0"
    if has_minor:
        return f"v{major}.{minor + 1}.0"
    if has_patch:
        return f"v{major}.{minor}.{patch + 1}"
    return current_tag   # no version-bumping commits

if __name__ == "__main__":
    current = subprocess.check_output(
        ["git", "describe", "--tags", "--abbrev=0"], text=True
    ).strip()
    next_ver = compute_next_version(current)
    print(next_ver)
